    uint8_t* bias = (uint8_t*)AscendC::GmAlloc(biasFileSize);
    uint8_t* c = (uint8_t*)AscendC::GmAlloc(cFileSize);
    uint8_t* tiling = (uint8_t*)AscendC::GmAlloc(tilingFileSize);
